#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long xor_sum = 0;
        for(int i=1;i<=N;i++){
            long long a; scanf("%lld", &a);
            if(a & 1LL) xor_sum ^= (long long)(N - i);
        }
        if(xor_sum) printf("Chef\n");
        else printf("Cook\n");
    }
    return 0;
}

