#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        xor = 0
        for i in range(1, N + 1):
            a = int(next(it))
            if a & 1:
                xor ^= (N - i)
        out_lines.append('Chef' if xor else 'Cook')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

